/* global console, process */
/*
 * over-air-braid.mjs — transmit each of the 6 hexon noise-colors as REAL
 * colored NOISE over the air through the SDR bench, capture on an RTL-SDR,
 * FFT the capture, measure the spectral slope, and check that each color's
 * slope SURVIVES the radio channel.
 *
 * This is the hardware witness for aeon-hexon-braid/hexon-braid.mjs: the
 * spectral-color ladder (brown +2 / pink +1 / white 0 / blue -1 / violet -2 /
 * grey perceptual, PSD ~ 1/f^beta) is not just a numeric construction — each
 * color radiates as a distinguishable RF noise texture on 433.92 MHz ISM and
 * its spectral exponent is recoverable from a Realtek RTL2832U capture.
 *
 * The .mjs uses ONE shared fft() / coloredNoise() lifted from hexon-braid.mjs.
 *
 * Two phases:
 *   gen       — write a colored-noise int16 IQ file per color (no RF).
 *   analyze   — load an rtl_u8 capture, FFT a baseband window, measure beta.
 * The orchestrating shell (braid-over-air.sh) keys the Pluto + captures
 * between these two phases. This file is pure compute (Node-only, no libiio).
 *
 *   node over-air-braid.mjs gen     <color> <iq16-out> [N]
 *   node over-air-braid.mjs analyze <color> <u8-capture> [target-beta]
 *   node over-air-braid.mjs colors                       # print color list
 */

import fs from 'node:fs';

// ---- shared FFT (radix-2, in place) — verbatim from hexon-braid.mjs ----
function mulberry32(seed) {
  let a = seed >>> 0;
  return () => {
    a |= 0; a = (a + 0x6d2b79f5) | 0;
    let t = Math.imul(a ^ (a >>> 15), 1 | a);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

function fft(re, im, inverse) {
  const n = re.length;
  for (let i = 1, j = 0; i < n; i++) {
    let bit = n >> 1;
    for (; j & bit; bit >>= 1) j ^= bit;
    j ^= bit;
    if (i < j) { [re[i], re[j]] = [re[j], re[i]]; [im[i], im[j]] = [im[j], im[i]]; }
  }
  for (let len = 2; len <= n; len <<= 1) {
    const ang = ((2 * Math.PI) / len) * (inverse ? 1 : -1);
    const wr = Math.cos(ang), wi = Math.sin(ang);
    for (let i = 0; i < n; i += len) {
      let cr = 1, ci = 0;
      for (let k = 0; k < len >> 1; k++) {
        const ar = re[i + k], ai = im[i + k];
        const br = re[i + k + (len >> 1)] * cr - im[i + k + (len >> 1)] * ci;
        const bi = re[i + k + (len >> 1)] * ci + im[i + k + (len >> 1)] * cr;
        re[i + k] = ar + br; im[i + k] = ai + bi;
        re[i + k + (len >> 1)] = ar - br; im[i + k + (len >> 1)] = ai - bi;
        const ncr = cr * wr - ci * wi; ci = cr * wi + ci * wr; cr = ncr;
      }
    }
  }
  if (inverse) for (let i = 0; i < n; i++) { re[i] /= n; im[i] /= n; }
}

// ---- colored noise: white -> FFT -> scale bin by f^(-beta/2) -> IFFT (real) ----
// verbatim from hexon-braid.mjs
function coloredNoise(N, beta, rng, perceptualGrey = false) {
  const re = new Array(N), im = new Array(N).fill(0);
  for (let i = 0; i < N; i++) re[i] = rng() * 2 - 1;
  fft(re, im, false);
  for (let k = 0; k < N; k++) {
    const f = k <= N / 2 ? k : N - k;
    let scale;
    if (perceptualGrey) {
      const peak = N / 8;
      scale = f === 0 ? 0 : 1 / (1 + Math.abs(Math.log((f + 1) / (peak + 1))));
    } else {
      scale = f === 0 ? 0 : Math.pow(f, -beta / 2);
    }
    re[k] *= scale; im[k] *= scale;
  }
  fft(re, im, true);
  return re.slice();
}

// ---- the HEXON (target spectral exponents) — from hexon-braid.mjs ----
const HEXON = [
  { name: 'brown', beta: 2, grey: false },
  { name: 'violet', beta: -2, grey: false },
  { name: 'pink', beta: 1, grey: false },
  { name: 'blue', beta: -1, grey: false },
  { name: 'white', beta: 0, grey: false },
  { name: 'grey', beta: 0, grey: true },
];
function colorByName(name) {
  const c = HEXON.find((h) => h.name === name);
  if (!c) { console.error(`unknown color: ${name}`); process.exit(2); }
  return c;
}

// ---- Pluto IQ scale (matches rtlsdr-mock-sim/pluto-tx.ts PLUTO_TX_SCALE) ----
const PLUTO_TX_SCALE = 8192;

// Hilbert-ish 90 degree shift: Q = the colored sample series delayed by one,
// so the noise is a genuine complex (single-sideband-ish) baseband — not a real
// signal mirrored into both sidebands (which would make the PSD symmetric and
// erase the slope sign). We build I from one colored stream and Q from a second
// independent colored stream of the SAME beta, giving a circularly-symmetric
// complex colored process whose one-sided spectrum carries the slope.
function genIqInt16(color, N) {
  const seedI = 0x4e57 ^ (color.name.length * 131);
  const seedQ = 0x9e37 ^ (color.name.length * 257);
  const ci = coloredNoise(N, color.beta, mulberry32(seedI), color.grey);
  const cq = coloredNoise(N, color.beta, mulberry32(seedQ), color.grey);
  // normalize each to unit RMS so the gain into the DAC is consistent per color
  const rms = (a) => Math.sqrt(a.reduce((s, v) => s + v * v, 0) / a.length) || 1;
  const ri = rms(ci), rq = rms(cq);
  const buf = Buffer.allocUnsafe(N * 4); // int16 LE interleaved I,Q
  for (let k = 0; k < N; k++) {
    let i = Math.round((ci[k] / ri) * 0.3 * PLUTO_TX_SCALE);
    let q = Math.round((cq[k] / rq) * 0.3 * PLUTO_TX_SCALE);
    i = Math.max(-32767, Math.min(32767, i));
    q = Math.max(-32767, Math.min(32767, q));
    buf.writeInt16LE(i, k * 4);
    buf.writeInt16LE(q, k * 4 + 2);
  }
  return buf;
}

// ---- measure beta of a complex baseband from an rtl_u8 capture ----
// rtl_sdr u8 is offset-binary interleaved I,Q: sample = byte - 127.5.
// The two-sided complex spectrum of a slope-beta process has, on the LO carrier,
// most power near DC; we measure the log-log slope of the magnitude spectrum
// across the occupied baseband, excluding DC and the band edges (DC spur, alias
// roll-off). measured beta = -slope of log PSD vs log frequency-offset.
function analyzeCapture(u8, target) {
  const total = (u8.length / 2) | 0;
  // pick a power-of-two window from the middle of the capture (avoid edges)
  let W = 1 << Math.floor(Math.log2(Math.min(total, 65536)));
  if (W < 1024) { console.error('capture too small'); process.exit(3); }
  const start = Math.max(0, ((total - W) >> 1));
  // average PSD over several windows for a smoother estimate
  const nWin = Math.min(16, Math.floor(total / W));
  const accMag = new Float64Array(W);
  for (let w = 0; w < nWin; w++) {
    const off = (w * W) % Math.max(1, total - W);
    const base = off;
    const re = new Array(W), im = new Array(W);
    for (let k = 0; k < W; k++) {
      const idx = (base + k);
      re[k] = u8[idx * 2] - 127.5;
      im[k] = u8[idx * 2 + 1] - 127.5;
    }
    // Hann window to control spectral leakage
    for (let k = 0; k < W; k++) {
      const hw = 0.5 - 0.5 * Math.cos((2 * Math.PI * k) / (W - 1));
      re[k] *= hw; im[k] *= hw;
    }
    fft(re, im, false);
    for (let k = 0; k < W; k++) accMag[k] += re[k] * re[k] + im[k] * im[k];
  }

  // Build a one-sided PSD as a function of |frequency offset from DC|.
  // bins: k in [1..W/2) are positive offsets; (W-k) are negative. Fold them.
  const half = W >> 1;
  const psd = new Float64Array(half);
  for (let k = 1; k < half; k++) psd[k] = (accMag[k] + accMag[W - k]) / 2;

  // Occupied band: our baseband noise fills the DAC bandwidth (~rf_bandwidth).
  // Exclude: the first few bins (DC spur + LO leakage) and the upper edge
  // (k > hiK; anti-alias / channel roll-off). We start the fit just above the
  // DC spur (k>=4) rather than well inside the band, because steep colors
  // (brown beta +2) carry almost all their power in the lowest occupied bins —
  // dropping that region erases the very slope we are trying to measure.
  const loK = Math.max(4, Math.floor(half * 0.006));
  const hiK = Math.floor(half * 0.40);
  let sx = 0, sy = 0, sxx = 0, sxy = 0, n = 0;
  for (let k = loK; k <= hiK; k++) {
    if (psd[k] <= 0) continue;
    const x = Math.log(k), y = Math.log(psd[k]);
    sx += x; sy += y; sxx += x * x; sxy += x * y; n++;
  }
  const slope = (n * sxy - sx * sy) / (n * sxx - sx * sx);
  const beta = -slope;
  return { beta, slope, W, nWin, loK, hiK, n, target };
}

function readU8(path) {
  return new Uint8Array(fs.readFileSync(path));
}

// ---- CLI ----
function main() {
  const [cmd, a, b, c] = process.argv.slice(2);
  if (cmd === 'colors') {
    for (const h of HEXON) {
      const tag = h.grey ? 'perceptual' : (h.beta >= 0 ? '+' : '') + h.beta;
      console.log(`${h.name} ${tag}`);
    }
    return;
  }
  if (cmd === 'gen') {
    const color = colorByName(a);
    const out = b;
    const N = c ? parseInt(c, 10) : 262144;
    const buf = genIqInt16(color, N);
    fs.writeFileSync(out, buf);
    console.log(JSON.stringify({ ok: true, color: color.name, beta: color.beta, grey: color.grey, samples: N, bytes: buf.length, out }));
    return;
  }
  if (cmd === 'analyze') {
    const color = colorByName(a);
    const u8 = readU8(b);
    const target = c !== undefined ? parseFloat(c) : color.beta;
    const r = analyzeCapture(u8, target);
    console.log(JSON.stringify({ ok: true, color: color.name, targetBeta: color.grey ? null : color.beta, measuredBeta: r.beta, slope: r.slope, fitBins: r.n, window: r.W }));
    return;
  }
  console.error('usage: over-air-braid.mjs gen|analyze|colors ...');
  process.exit(2);
}
main();
